  { value: "table", label: "Table" },
  { value: "board", label: "Board" },
];

interface TicketsFiltersDrawerProps {
  onSortPresetChange: (next: SortPreset) => void;
  onStatusFilterChange: (next: StatusFilter) => void;
  onToggleColumn: (id: TicketColumnId) => void;
  onViewChange: (next: ViewMode) => void;
  sortPreset: SortPreset;
  statusFilter: StatusFilter;
  view: ViewMode;
  visibleColumns: Set<TicketColumnId>;
}

export function TicketsFiltersDrawer({
  sortPreset,
  onSortPresetChange,
  statusFilter,
  onStatusFilterChange,
  view,
  onViewChange,
  visibleColumns,
  onToggleColumn,
}: TicketsFiltersDrawerProps) {
  const [open, setOpen] = useState(false);
  const [step, setStep] = useState(0);

  return (
    <Drawer
      onOpenChange={(isOpen) => {
        setOpen(isOpen);
        if (!isOpen) {
          setStep(0);
        }
      }}
      open={open}
    >
      <DrawerTrigger render={<Button variant="outline" />}>
        <FilterIcon className="size-4" />
        Filters
      </DrawerTrigger>
      <DrawerContent>
        <div className="mx-auto w-full max-w-sm">
          <Stepper onValueChange={setStep} value={step}>
            <StepperContent>
              <StepperStep>
                <DrawerHeader>
                  <DrawerTitle className="text-center">Filters</DrawerTitle>
                </DrawerHeader>
                <FilterMenu
                  sortLabel={sortPresetLabels[sortPreset]}
                  statusLabel={
                    statusFilter === "all"
                      ? "All Statuses"
                      : statusLabels[statusFilter]
                  }
                  viewLabel={view === "board" ? "Board" : "Table"}
                  visibleColumnsCount={visibleColumns.size}
                />
                <DrawerFooter>
                  <Button className="w-full" onClick={() => setOpen(false)}>
                    Apply
                  </Button>
                </DrawerFooter>
              </StepperStep>

              <StepperStep>
                <SubHeader title="Sort by" />
                <div className="pb-4">
                  <RadioGroup
                    className="gap-0 divide-y divide-border-muted"
                    onValueChange={(val) => {
                      if (val) {
                        onSortPresetChange(val as SortPreset);
                      }
                    }}
                    value={sortPreset}
                  >
                    {SORT_OPTIONS.map((preset) => (
                      // biome-ignore lint/a11y/noLabelWithoutControl: control is inside label
                      <label
                        className="flex h-12 cursor-pointer items-center gap-3 px-4"
                        key={preset}
                      >
                        <RadioGroupItem value={preset} />
                        <span className="text-sm">
                          {sortPresetLabels[preset]}
                        </span>
                      </label>
                    ))}
                  </RadioGroup>
                </div>
              </StepperStep>

              <StepperStep>
                <SubHeader title="Status" />
                <div className="pb-4">
                  <RadioGroup
                    className="gap-0 divide-y divide-border-muted"
                    onValueChange={(val) => {
                      if (val) {
                        onStatusFilterChange(val as StatusFilter);
                      }
                    }}
                    value={statusFilter}
                  >
                    {STATUS_OPTIONS.map((option) => (
                      // biome-ignore lint/a11y/noLabelWithoutControl: control is inside label
                      <label
                        className="flex h-12 cursor-pointer items-center gap-3 px-4"
                        key={option.value}
                      >
                        <RadioGroupItem value={option.value} />
                        <span className="text-sm">{option.label}</span>
                      </label>
                    ))}
                  </RadioGroup>
                </div>
              </StepperStep>

              <StepperStep>
                <SubHeader title="Columns" />
                <div className="divide-y divide-border-muted pb-4">
                  {ticketColumns.map((column) => (
                    // biome-ignore lint/a11y/noLabelWithoutControl: control is inside label
                    <label
                      className="flex h-12 cursor-pointer items-center gap-3 px-4"
                      key={column.id}
                    >
                      <Checkbox
                        checked={visibleColumns.has(column.id)}
                        onCheckedChange={() => onToggleColumn(column.id)}
                      />
                      <span className="text-sm">{column.label}</span>
                    </label>
                  ))}
                </div>
              </StepperStep>

              <StepperStep>
                <SubHeader title="View" />
                <div className="pb-4">
                  <RadioGroup
                    className="gap-0 divide-y divide-border-muted"
                    onValueChange={(val) => {
                      if (val === "table" || val === "board") {
                        onViewChange(val);
                      }
                    }}
                    value={view}
                  >
                    {VIEW_OPTIONS.map((option) => (
                      // biome-ignore lint/a11y/noLabelWithoutControl: control is inside label
                      <label
                        className="flex h-12 cursor-pointer items-center gap-3 px-4"
                        key={option.value}
                      >
                        <RadioGroupItem value={option.value} />
                        <span className="text-sm">{option.label}</span>
                      </label>
                    ))}
                  </RadioGroup>
                </div>
              </StepperStep>
            </StepperContent>
          </Stepper>
        </div>
      </DrawerContent>
    </Drawer>
  );
}

function FilterMenu({
  sortLabel,
  statusLabel,
  viewLabel,
  visibleColumnsCount,
}: {
  sortLabel: string;
  statusLabel: string;
  viewLabel: string;
  visibleColumnsCount: number;
}) {
  const { goTo } = useStepper();
  const items: { label: string; value: string; step: number }[] = [
    { label: "Sort by", value: sortLabel, step: 1 },
    { label: "Status", value: statusLabel, step: 2 },
    {
      label: "Columns",
      value: `${visibleColumnsCount} visible`,
      step: 3,
    },
    { label: "View", value: viewLabel, step: 4 },
  ];

  return (
    <div className="divide-y divide-border-muted">
      {items.map((item) => (
        <button
          className="flex h-12 w-full cursor-pointer items-center justify-between gap-3 px-4 text-left active:text-muted-foreground"
          key={item.step}
          onClick={() => goTo(item.step)}
          type="button"
        >
          <span className="font-medium text-sm">{item.label}</span>
          <span className="ml-auto inline-flex min-w-0 items-center gap-2 text-muted-foreground text-sm">
            <span className="truncate">{item.value}</span>
            <ChevronRightIcon className="size-4 shrink-0" />
          </span>
        </button>
      ))}
    </div>
  );
}

function SubHeader({ title }: { title: string }) {
  const { goTo } = useStepper();
  return (
    <DrawerHeader>
      <div className="flex items-center gap-2">
        <Button
          aria-label="Back"
          className="-ml-1"
          onClick={() => goTo(0)}
          size="icon-xs"
          variant="ghost"
        >
          <ArrowLeftIcon className="size-4" />
        </Button>
        <DrawerTitle>{title}</DrawerTitle>
      </div>
    </DrawerHeader>
  );
}

"use client";

import {
  ChevronLeftIcon,
  ChevronRightIcon,
  ChevronsLeftIcon,
  ChevronsRightIcon,
} from "lucide-react";
import { useId } from "react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

const PAGE_SIZE_OPTIONS = [5, 10, 20, 50];

interface TicketsPaginationProps {
  onPageIndexChange: (next: number) => void;
  onPageSizeChange: (next: number) => void;
  pageIndex: number;
  pageSize: number;
  selectedCount: number;
  totalCount: number;
}

export function TicketsPagination({
  totalCount,
  selectedCount,
  pageIndex,
  pageSize,
  onPageIndexChange,
  onPageSizeChange,
}: TicketsPaginationProps) {
  const pageCount = Math.max(1, Math.ceil(totalCount / pageSize));
  const canGoPrev = pageIndex > 0;
  const canGoNext = pageIndex < pageCount - 1;
  const pageSizeId = useId();

  return (
    <div className="flex items-center justify-between gap-4 px-2">
      <div className="hidden flex-1 text-muted-foreground text-sm lg:block">
        {selectedCount} of {totalCount} row(s) selected.
      </div>

      <div className="flex w-full items-center gap-6 lg:w-fit lg:gap-8">
        <div className="hidden items-center gap-2 lg:flex">
          <Label className="font-medium text-sm" htmlFor={pageSizeId}>
            Rows per page
          </Label>
          <Select
            onValueChange={(value) => {
              if (value) {
                onPageSizeChange(Number(value));
              }
            }}
            value={String(pageSize)}
          >
            <SelectTrigger className="w-20" id={pageSizeId} size="sm">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectGroup>
                {PAGE_SIZE_OPTIONS.map((option) => (
                  <SelectItem key={option} value={String(option)}>
                    {option}
                  </SelectItem>
                ))}
              </SelectGroup>
            </SelectContent>
          </Select>
        </div>

        <div className="flex w-fit items-center justify-center font-medium text-sm">
          Page {pageIndex + 1} of {pageCount}
        </div>

        <div className="ml-auto flex items-center gap-2 lg:ml-0">
          <Button
            aria-label="Go to first page"
            className="hidden lg:flex"
            disabled={!canGoPrev}
            onClick={() => onPageIndexChange(0)}
            size="icon-sm"
            variant="outline"
          >
            <ChevronsLeftIcon />
          </Button>
          <Button
            aria-label="Go to previous page"
            disabled={!canGoPrev}
            onClick={() => onPageIndexChange(pageIndex - 1)}
            size="icon-sm"
            variant="outline"
          >
            <ChevronLeftIcon />
          </Button>
          <Button
            aria-label="Go to next page"
            disabled={!canGoNext}
            onClick={() => onPageIndexChange(pageIndex + 1)}
            size="icon-sm"
            variant="outline"
          >
            <ChevronRightIcon />
          </Button>
          <Button
            aria-label="Go to last page"
            className="hidden lg:flex"
            disabled={!canGoNext}
            onClick={() => onPageIndexChange(pageCount - 1)}
            size="icon-sm"
            variant="outline"
          >
            <ChevronsRightIcon />
          </Button>
        </div>
      </div>
    </div>
  );
}

